  ax1.text(x_pos, i, significance, va='center', \n                ha='left' if data['변화율(%)'] >= 0 else 'right',\n                fontsize=11, fontweight='bold', color='black')\n    \n    # 오른쪽: Cohen's d 효과 크기\n    ax2 = axes[1]\n    \n    # Cohen's d 절대값 기준 정렬\n    df_cohens_sorted = df_merged.sort_values('Cohen\\'s d', ascending=True).reset_index(drop=True)\n    \n    # 효과 크기 색상 (양수/음수 구분)\n    colors_cohens = ['#3B82F6' if x >= 0 else '#F59E0B' for x in df_cohens_sorted['Cohen\\'s d']]\n    \n    bars2 = ax2.barh(range(len(df_cohens_sorted)), df_cohens_sorted['Cohen\\'s d'], \n                     color=colors_cohens, alpha=0.8)\n    \n    ax2.set_yticks(range(len(df_cohens_sorted)))\n    ax2.set_yticklabels(df_cohens_sorted['역량'], fontsize=10)\n    ax2.set_xlabel('Cohen\\'s d (효과 크기)', fontsize=12, fontweight='bold')\n    ax2.set_title('역량별 효과 크기 (Cohen\\'s d)', fontsize=14, fontweight='bold', pad=15)\n    ax2.axvline(x=0, color='black', linestyle='-', linewidth=1.5)\n    \n    # 효과 크기 기준선\n    ax2.axvline(x=0.2, color='gray', linestyle='--', linewidth=1, alpha=0.5, label='작은 효과')\n    ax2.axvline(x=-0.2, color='gray', linestyle='--', linewidth=1, alpha=0.5)\n    ax2.axvline(x=0.5, color='gray', linestyle=':', linewidth=1, alpha=0.5, label='중간 효과')\n    ax2.axvline(x=-0.5, color='gray', linestyle=':', linewidth=1, alpha=0.5)\n    ax2.axvline(x=0.8, color='gray', linestyle='-.', linewidth=1, alpha=0.5, label='큰 효과')\n    ax2.axvline(x=-0.8, color='gray', linestyle='-.', linewidth=1, alpha=0.5)\n    \n    ax2.legend(fontsize=9, loc='lower right')\n    ax2.grid(axis='x', linestyle='--', alpha=0.3)\n    \n    # 값 표시\n    for i, (bar, val) in enumerate(zip(bars2, df_cohens_sorted['Cohen\\'s d'])):\n        x_pos = val + (0.05 if val >= 0 else -0.05)\n        ax2.text(x_pos, i, f'{val:.2f}', va='center', \n                ha='left' if val >= 0 else 'right', fontsize=9)\n    \n    plt.tight_layout()\n    plt.show()\n    \n    print(\"\\n범례:\")\n    print(\"- 진한 색상: 통계